import { useState } from "react";
import classes from "./AddFriendInput.module.css";

const AddFriendInput = (props) => {
  const [enteredValue, setEnteredValue] = useState("");

  let isEmpty = true;
  if (enteredValue !== "") {
    isEmpty = false;
  }

  // Sends message
  const submitHandler = (event) => {
    props.submitMessage(enteredValue);
    setEnteredValue("");
  };

  const onChangeHandler = (event) => {
    setEnteredValue(event.target.value);
  };

  return (
    <div className={classes["input-wrapper"]}>
      {isEmpty && (
        <div className={`${classes["placeholder"]} ${classes["text-padding"]}`}>
          Message
        </div>
      )}
      <input
        onChange={onChangeHandler}
        value={enteredValue}
        className={`${classes["text"]} ${classes["text-padding"]}`}
      ></input>
    </div>
  );
};

export default AddFriendInput;
